#include "portable.h"

#include <stdio.h>
#include <ac/stdlib.h>

#include <ac/string.h>
#include <ac/time.h>

#include "ldap-int.h"

#include <ldap_schema.h>

static const char EndOfInput[] = "end of input";

static const char *
choose_name( char *names[], const char *fallback )
{
	return (names != NULL && names[0] != NULL) ? names[0] : fallback;
}

LDAP_CONST char *
ldap_syntax2name( LDAPSyntax * syn )
{
	if (!syn) return NULL;
	return( syn->syn_oid );
