  1115→		start++;
  1116→	}
  1117→	/* Each iteration of this loop gets one decimal string */
  1118→	while (**sp) {
  1119→		if ( !LDAP_DIGIT(**sp) ) {
  1120→			/*
  1121→			 * Initial char is not a digit or char after dot is
  1122→			 * not a digit
  1123→			 */
  1124→			*code = LDAP_SCHERR_NODIGIT;
  1125→			return NULL;
  1126→		}
  1127→		(*sp)++;
